import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Model X',
        data: [92, 60, 88, 95, 55, 90],
      },
      {
        name: 'Model Y',
        data: [70, 95, 66, 78, 85, 72],
      },
      {
        name: 'Model Z',
        data: [80, 78, 82, 70, 68, 60],
      },
    ],
    options: {
      chart: {
        height: 350,
        type: 'radar',
      },
      title: {
        text: 'Smartphone Comparison',
      },
      stroke: {
        width: 2,
      },
      fill: {
        opacity: 0.1,
      },
      markers: {
        size: 0,
      },
      yaxis: {
        stepSize: 20,
      },
      xaxis: {
        categories: [
          'Performance',
          'Battery',
          'Camera',
          'Display',
          'Value',
          'Design',
        ],
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="radar"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
